class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || 'openid profile email';
    this.storageKey = config.storageKey || 'oauth_tokens';
  }

  generateCodeVerifier() {
    const array = new Uint32Array(28);
    crypto.getRandomValues(array);
    return btoa(String.fromCharCode(...array))
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=/g, '');
  }

  async generateCodeChallenge(codeVerifier) {
    const data = new TextEncoder().encode(codeVerifier);
    const digest = await crypto.subtle.digest('SHA-256', data);
    return btoa(String.fromCharCode(...new Uint8Array(digest)))
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=/g, '');
  }

  async initiateAuth() {
    const codeVerifier = this.generateCodeVerifier();
    const codeChallenge = await this.generateCodeChallenge(codeVerifier);
    
    sessionStorage.setItem('oauth_code_verifier', codeVerifier);
    
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
      state: this.generateState()
    });
    
    window.location.href = `${this.authorizationEndpoint}?${params}`;
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const storedState = sessionStorage.getItem('oauth_state');
    
    if (!code || state !== storedState) {
      throw new Error('Invalid OAuth callback');
    }
    
    const codeVerifier = sessionStorage.getItem('oauth_code_verifier');
    if (!codeVerifier) {
      throw new Error('Missing code verifier');
    }
    
    try {
      const tokenResponse = await fetch(this.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: this.redirectUri,
          code_verifier: codeVerifier
        })
      });
      
      if (!tokenResponse.ok) {
        throw new Error(`Token exchange failed: ${tokenResponse.status}`);
      }
      
      const tokens = await tokenResponse.json();
      this.storeTokens(tokens);
      sessionStorage.removeItem('oauth_code_verifier');
      sessionStorage.removeItem('oauth_state');
      
      return tokens;
    } catch (error) {
      sessionStorage.removeItem('oauth_code_verifier');
      sessionStorage.removeItem('oauth_state');
      throw error;
    }
  }

  generateState() {
    const array = new Uint32Array(10);
    crypto.getRandomValues(array);
    const state = btoa(String.fromCharCode(...array));
    sessionStorage.setItem('oauth_state', state);
    return state;
  }

  storeTokens(tokens) {
    const tokenData = {
      ...tokens,
      timestamp: Date.now()
    };
    localStorage.setItem(this.storageKey, JSON.stringify(tokenData));
  }

  getAccessToken() {
    const tokenData = localStorage.getItem(this.storageKey);
    if (!tokenData) return null;
    
    const data = JSON.parse(tokenData);
    return data.access_token;
  }

  async refreshAccessToken() {
    const tokenData = localStorage.getItem(this.storageKey);
    if (!tokenData) return null;
    
    const data = JSON.parse(tokenData);
    if (!data.refresh_token) return null;
    
    try {
      const response = await fetch(this.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: data.refresh_token
        })
      });
      
      if (!response.ok) {
        throw new Error(`Token refresh failed: ${response.status}`);
      }
      
      const tokens = await response.json();
      this.storeTokens(tokens);
      return tokens.access_token;
    } catch (error) {
      this.clearTokens();
      throw error;
    }
  }

  clearTokens() {
    localStorage.removeItem(this.storageKey);
  }

  async apiRequest(url, options = {}) {
    const accessToken = this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available');
    }
    
    const defaultOptions = {
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      }
    };
    
    const requestOptions = { ...defaultOptions, ...options };
    
    try {
      const response = await fetch(url, requestOptions);
      
      if (response.status === 401) {
        const refreshedToken = await this.refreshAccessToken();
        if (refreshedToken) {
          requestOptions.headers.Authorization = `Bearer ${refreshedToken}`;
          return fetch(url, requestOptions);
        }
      }
      
      if (!response.ok) {
        throw new Error(`API request failed: ${response.status}`);
      }
      
      return response.json();
    } catch (error) {
      throw error;
    }
  }
}

